2. using Microsoft.AspNetCore.Identity;
3. using Microsoft.EntityFrameworkCore;
4. using ShipmentTracker.Client.Pages;
5. using ShipmentTracker.Components;
6. using ShipmentTracker.Components.Account;
7. using ShipmentTracker.Data;
8. 
9. var builder = WebApplication.CreateBuilder(args);
10. 
11. // Add services to the container.
12. builder.Services.AddRazorComponents()
13.     .AddInteractiveServerComponents()
14.     .AddInteractiveWebAssemblyComponents()
15.     .AddAuthenticationStateSerialization();
16. 
17. builder.Services.AddCascadingAuthenticationState();
18. builder.Services.AddScoped<IdentityRedirectManager>();
19. builder.Services.AddScoped<AuthenticationStateProvider, IdentityRevalidatingAuthenticationStateProvider>();
20. 
21. builder.Services.AddAuthentication(options =>
22.     {
23.         options.DefaultScheme = IdentityConstants.ApplicationScheme;
24.         options.DefaultSignInScheme = IdentityConstants.ExternalScheme;
25.     })
26.     .AddIdentityCookies();
27. 
28. var connectionString = builder.Configuration.GetConnectionString("DefaultConnection") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");
29. builder.Services.AddDbContext<ApplicationDbContext>(options =>
30.     options.UseSqlite(connectionString));
31. builder.Services.AddDatabaseDeveloperPageExceptionFilter();
32. 
33. builder.Services.AddIdentityCore<ApplicationUser>(options =>
34.     {
35.         options.SignIn.RequireConfirmedAccount = true;
36.         options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
37.     })
38.     .AddEntityFrameworkStores<ApplicationDbContext>()
39.     .AddSignInManager()
40.     .AddDefaultTokenProviders();
