using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider services)
    {
        using var scope = services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        await db.Database.MigrateAsync();

        var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();
        string[] roles = ["Dispatcher", "Customer"];
        foreach (var role in roles)
        {
            if (!await roleManager.RoleExistsAsync(role))
                await roleManager.CreateAsync(new IdentityRole(role));
        }

        var userManager = scope.ServiceProvider.GetRequiredService<UserManager<ApplicationUser>>();

        // Seed a dispatcher account
        var dispatcher = await userManager.FindByEmailAsync("dispatcher@shipments.local");
        if (dispatcher is null)
        {
            dispatcher = new ApplicationUser
            {
                UserName = "dispatcher@shipments.local",
                Email = "dispatcher@shipments.local",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(dispatcher, "Dispatch1!");
            await userManager.AddToRoleAsync(dispatcher, "Dispatcher");
        }

        // Seed a customer account
        var customer = await userManager.FindByEmailAsync("customer@example.com");
        if (customer is null)
        {
            customer = new ApplicationUser
            {
                UserName = "customer@example.com",
                Email = "customer@example.com",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(customer, "Customer1!");
            await userManager.AddToRoleAsync(customer, "Customer");
        }

        // Seed shipments
        if (!await db.Shipments.AnyAsync())
        {
            var now = DateTime.UtcNow;
            db.Shipments.AddRange(
                new Shipment
                {
                    TrackingNumber = "TRK-001",
                    Origin = "New York, NY",
                    Destination = "Los Angeles, CA",
                    Status = ShipmentStatus.InTransit,
                    CreatedAtUtc = now.AddDays(-3),
                    EstimatedDeliveryUtc = now.AddDays(2),
                    CustomerEmail = "customer@example.com",
                    Notes = "Fragile — handle with care"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-002",
                    Origin = "Chicago, IL",
                    Destination = "Houston, TX",
                    Status = ShipmentStatus.Pending,
                    CreatedAtUtc = now.AddDays(-1),
                    EstimatedDeliveryUtc = now.AddDays(5),
                    CustomerEmail = "customer@example.com"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-003",
                    Origin = "Seattle, WA",
                    Destination = "Miami, FL",
                    Status = ShipmentStatus.Delivered,
                    CreatedAtUtc = now.AddDays(-10),
                    EstimatedDeliveryUtc = now.AddDays(-2),
                    CustomerEmail = "other@example.com"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-004",
                    Origin = "Denver, CO",
                    Destination = "Boston, MA",
                    Status = ShipmentStatus.OutForDelivery,
                    CreatedAtUtc = now.AddDays(-4),
                    EstimatedDeliveryUtc = now,
                    CustomerEmail = "customer@example.com"
                },
                new Shipment
                {
                    TrackingNumber = "TRK-005",
                    Origin = "San Francisco, CA",
                    Destination = "Phoenix, AZ",
                    Status = ShipmentStatus.PickedUp,
                    CreatedAtUtc = now.AddHours(-6),
                    EstimatedDeliveryUtc = now.AddDays(3),
                    CustomerEmail = "other@example.com"
                }
            );
            await db.SaveChangesAsync();
        }
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Http.HttpResults;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // GET all shipments — Dispatchers only
        group.MapGet("/", [Authorize(Roles = "Dispatcher")] async (ApplicationDbContext db, string? status) =>
        {
            var query = db.Shipments.AsQueryable();
            if (Enum.TryParse<ShipmentStatus>(status, true, out var s))
                query = query.Where(x => x.Status == s);

            var shipments = await query.OrderByDescending(x => x.CreatedAtUtc)
                .Select(x => ToDto(x))
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // GET shipments for the current customer
        group.MapGet("/my", async (ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            var email = user.FindFirstValue(ClaimTypes.Email)
                        ?? user.FindFirstValue(ClaimTypes.Name);

            var shipments = await db.Shipments
                .Where(x => x.CustomerEmail == email)
                .OrderByDescending(x => x.CreatedAtUtc)
                .Select(x => ToDto(x))
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // GET shipment by tracking number — any authenticated user
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(x => x.TrackingNumber == trackingNumber);

            return shipment is null
                ? Results.NotFound()
                : Results.Ok(ToDto(shipment));
        });

        // POST create shipment — Dispatchers only
        group.MapPost("/", [Authorize(Roles = "Dispatcher")] async (CreateShipmentRequest req, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMddHHmmss}-{Random.Shared.Next(1000, 9999)}",
                Origin = req.Origin,
                Destination = req.Destination,
                Status = ShipmentStatus.Pending,
                CreatedAtUtc = DateTime.UtcNow,
                EstimatedDeliveryUtc = req.EstimatedDeliveryUtc,
                CustomerEmail = req.CustomerEmail,
                Notes = req.Notes
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();

            return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", ToDto(shipment));
        });

        // PUT update shipment — Dispatchers only
        group.MapPut("/{id:int}", [Authorize(Roles = "Dispatcher")] async (int id, UpdateShipmentRequest req, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = req.Status;
            shipment.EstimatedDeliveryUtc = req.EstimatedDeliveryUtc;
            shipment.Notes = req.Notes;
            await db.SaveChangesAsync();

            return Results.Ok(ToDto(shipment));
        });
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        CreatedAtUtc = s.CreatedAtUtc,
        EstimatedDeliveryUtc = s.EstimatedDeliveryUtc,
        CustomerEmail = s.CustomerEmail,
        Notes = s.Notes
    };
}

