<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="() => showCreate = !showCreate">
            @(showCreate ? "Cancel" : "＋ New Shipment")
        </button>
    </div>
</div>

@if (showCreate)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="createShipment">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Customer Email</label>
                        <InputText class="form-control" @bind-Value="newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Estimated Delivery (UTC)</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal"
                                   @bind-Value="newShipment.EstimatedDeliveryUtc" />
                    </div>
                    <div class="col-12">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="newShipment.Notes" />
                    </div>
                    <div class="col-12">
                        <button type="submit" class="btn btn-success" disabled="@creating">
                            @(creating ? "Creating…" : "Create")
                        </button>
                    </div>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments…</em></p>
}
else if (shipments.Length == 0)
{
    <div class="alert alert-info">No shipments found.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Customer</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in shipments)
                {
                    <tr>
                        <td><strong>@s.TrackingNumber</strong></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td><span class="badge @StatusBadge(s.Status)">@s.Status</span></td>
                        <td>@s.CustomerEmail</td>
                        <td>@s.EstimatedDeliveryUtc?.ToString("g")</td>
                        <td>
                            @if (editingId == s.Id)
                            {
                                <div class="d-flex gap-1 align-items-center">
                                    <select class="form-select form-select-sm" style="width:auto"
                                            @bind="editStatus">
                                        @foreach (var st in Enum.GetValues<ShipmentStatus>())
                                        {
                                            <option value="@st">@st</option>
                                        }
                                    </select>
                                    <button class="btn btn-sm btn-success" @onclick="() => SaveEdit(s)">Save</button>
                                    <button class="btn btn-sm btn-secondary" @onclick="() => editingId = null">✕</button>
                                </div>
                            }
                            else
                            {
                                <button class="btn btn-sm btn-outline-primary"
                                        @onclick="() => StartEdit(s)">Edit</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private ShipmentDto[]? shipments;
    private string statusFilter = "";
    private bool showCreate;
    private bool creating;
    private CreateShipmentRequest newShipment = new();
    private int? editingId;
    private ShipmentStatus editStatus;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        var url = string.IsNullOrEmpty(statusFilter)
            ? "/api/shipments"
            : $"/api/shipments?status={statusFilter}";
        shipments = await Http.GetFromJsonAsync<ShipmentDto[]>(url);
    }

    private async Task CreateShipment()
    {
        creating = true;
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            newShipment = new();
            showCreate = false;
            await LoadShipments();
        }
        creating = false;
    }

    private void StartEdit(ShipmentDto s)
    {
        editingId = s.Id;
        editStatus = s.Status;
    }

    private async Task SaveEdit(ShipmentDto s)
    {
        var req = new UpdateShipmentRequest
        {
            Status = editStatus,
            EstimatedDeliveryUtc = s.EstimatedDeliveryUtc,
            Notes = s.Notes
        };
        await Http.PutAsJsonAsync($"/api/shipments/{s.Id}", req);
        editingId = null;
        await LoadShipments();
    }

    private static string StatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
